(window.webpackJsonp=window.webpackJsonp||[]).push([[17],{370:function(t,e){"use strict";e.__esModule=!0,e.default={render:function(){return this.$createElement("div",{staticClass:"theme-default-content content__default",domProps:{innerHTML:"<h2 id=\"graduate-studies\"><a href=\"#graduate-studies\" class=\"header-anchor\">#</a> Graduate Studies</h2>\n<p>我们实验室主要围绕心脑血管影像分析、眼科医学影像、医学大模型后训练与 Agent 方向开展研究，聚焦医工交叉的临床真实问题，既有基础算法研究，也有和临床医院合作的转化课题。</p>\n<h3 id=\"research-directions\"><a href=\"#research-directions\" class=\"header-anchor\">#</a> Research Directions</h3>\n<table><thead><tr><th>方向</th><th>内容</th></tr></thead><tbody><tr><td>心脑血管影像分析</td><td>血管结构、功能与疾病相关影像标志物建模。</td></tr><tr><td>眼科医学影像</td><td>围绕眼底、OCT/OCTA 等影像开展分析与临床应用研究。</td></tr><tr><td>医学大模型后训练与 Agent</td><td>面向医学场景的大模型后训练、多模态推理、工具调用和医疗 Agent。</td></tr></tbody></table>\n<h3 id=\"candidate-profile\"><a href=\"#candidate-profile\" class=\"header-anchor\">#</a> 希望你是</h3>\n<ul><li>2027 届应届本科生，能获得推免资格。</li><li>对医学影像、医学大模型或医工交叉方向有明确兴趣，有较强的代码能力。</li><li>做事踏实，愿意长期投入科研，遇到问题能主动沟通。</li><li>有论文成果或开源社区贡献。</li></ul>\n<h3 id=\"admissions\"><a href=\"#admissions\" class=\"header-anchor\">#</a> 招生信息</h3>\n<table><tbody><tr><th>所在单位</th><td>南京大学（苏州校区）生物医学工程学院</td></tr><tr><th>系统招生导师</th><td>新 PI 张炯教授</td></tr><tr><th>招生名额</th><td>本年度有数个博士招生名额。</td></tr><tr><th>直博申请</th><td>直博生需要参加现代工程与应用科学学院（034）计算机应用技术方向的夏令营。</td></tr><tr><th>导师主页</th><td><a href=\"https://jiongzhang-john.github.io\" target=\"_blank\" rel=\"noopener noreferrer\">https://jiongzhang-john.github.io</a></td></tr></tbody></table>"}})}}}}]);